 1	import { PersistentVolumeClaimModel, VolumeSnapshotModel } from '@kubevirt-ui/kubevirt-api/console';
 2	import DataImportCronModel from '@kubevirt-ui/kubevirt-api/console/models/DataImportCronModel';
 3	import DataSourceModel from '@kubevirt-ui/kubevirt-api/console/models/DataSourceModel';
 4	import VirtualMachineClusterPreferenceModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineClusterPreferenceModel';
 5	import { K8sVerb, useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 6	
 7	type UseCanCreateBootableVolume = (namespace: string) => {
 8	  canCreateDS: boolean;
 9	  canCreatePVC: boolean;
10	  canCreateSnapshots: boolean;
11	  canListInstanceTypesPreference: boolean;
12	  loading: boolean;
13	};
14	
15	const useCanCreateBootableVolume: UseCanCreateBootableVolume = (namespace) => {
16	  const [canCreatePVC, loadingPVC] = useAccessReview({
17	    group: PersistentVolumeClaimModel.apiGroup,
18	    namespace: namespace,
19	    resource: PersistentVolumeClaimModel.plural,
20	    verb: 'create' as K8sVerb,
21	  });
22	  const [canCreateSnapshots, loadingShapshots] = useAccessReview({
23	    group: VolumeSnapshotModel.apiGroup,
24	    namespace: namespace,
25	    resource: VolumeSnapshotModel.plural,
26	    verb: 'create' as K8sVerb,
27	  });
28	
29	  const [canCreateDS, loadingDS] = useAccessReview({
30	    group: DataSourceModel.apiGroup,
31	    namespace: namespace,
32	    resource: DataSourceModel.plural,
33	    verb: 'create' as K8sVerb,
34	  });
35	
36	  const [canCreateDIC, loadingDIC] = useAccessReview({
37	    group: DataImportCronModel.apiGroup,
38	    namespace: namespace,
39	    resource: DataImportCronModel.plural,
40	    verb: 'create' as K8sVerb,
41	  });
42	
43	  const [canListInstanceTypesPreference, loadingInstanceTypesPreference] = useAccessReview({
44	    group: VirtualMachineClusterPreferenceModel.apiGroup,
45	    resource: VirtualMachineClusterPreferenceModel.plural,
46	    verb: 'list' as K8sVerb,
47	  });
48	
49	  return {
50	    canCreateDS: canCreateDS && canCreateDIC,
51	    canCreatePVC,
52	    canCreateSnapshots,
53	    canListInstanceTypesPreference,
54	    loading:
55	      loadingPVC || loadingDS || loadingDIC || loadingInstanceTypesPreference || loadingShapshots,
56	  };
57	};
58	
59	export default useCanCreateBootableVolume;

